UPDATE
		NF_TRADINFO_MGT
   SET 
		SSA_TRUTH = #{ssaTruth},
		SSA_CONFIDENCE = #{ssaConfidence}
WHERE
		CUST_NO = #{custNo}
AND 	TRAD_NO = #{tradNo}

UPDATE
	NF_TRADINFO_MGT
SET
	ID_CARD_CD = #{idCardCd}

		,CALL_CNTR_STS_CD = #{callCntrStsCd}


		,PRGRSS_STS_CD = #{prgrssStsCd}


		,SEQ_NO = #{seqNo}


		,CNNCTN_WAY = #{cnnctnWayDynamic}

WHERE
	CUST_NO = #{custNo} 
	AND TRAD_NO = #{tradNo}

mapper.insert:
MERGE INTO NF_CNNCTN_TRADINFO_MGT X USING ( SELECT COUNT(*) COUNT FROM NF_TRADINFO_MGT WHERE TRAD_NO = #{tradNo} AND PRGRSS_STS_CD = 'PRGS' ) Y ON ( Y.COUNT > 0 AND X.TRAD_NO = #{tradNo} ) WHEN MATCHED THEN UPDATE SET X.LST_CHNG_DT = CURRENT TIMESTAMP, X.CNNCTN_TRAD_NO = #{cnnctnTradNo}
,CNNCTN_WAY = #{cnnctnWayDynamic}
,X.CNNCTN_SIGN_ID = #{cnnctnSignId}
WHEN NOT MATCHED THEN INSERT( X.CNNCTN_WAY, X.TRAD_NO, X.CNNCTN_TRAD_NO, X.CNNCTN_SND_YN, X.LST_CHNG_DT, X.INIT_REGIST_DT
,X.CNNCTN_LOAN_LMT_AMT
,X.CNNCTN_SIGN_ID
) VALUES ( #{cnnctnWay}, (SELECT MAX(TRAD_NO) AS TRAD_NO FROM NF_TRADINFO_MGT WHERE CUST_NO = #{custNo}), #{cnnctnTradNo}, 'N', CURRENT TIMESTAMP, CURRENT TIMESTAMP
,#{cnnctnLoanLmtAmt}
,#{cnnctnSignId}
)

