	NF_TRADINFO_MGT 
SET 
	ID_CARD_CNT = #{idCardCnt}

		,ID_CARD_REQ_DT = #{idCardReqDt}

WHERE
	CUST_NO = #{custNo}
	AND TRAD_NO = #{tradNo}
